#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        char S[105]; scanf("%s", S);
        long long visited[205];
        int cnt = 0;
        long long cur = X;
        visited[cnt++] = cur;
        for (int i = 0; i < N; ++i) {
            if (S[i] == 'L') cur--;
            else cur++;
            bool already = false;
            for (int j = 0; j < cnt; ++j) {
                if (visited[j] == cur) { already = true; break; }
            }
            if (!already) visited[cnt++] = cur;
        }
        printf("%d\n", cnt);
    }
    return 0;
}

