    while (T--) {
        int N; long long X; cin >> N >> X;
        string S; cin >> S;
        unordered_set<long long> visited;
        visited.reserve(N*2+5);
        long long cur = X;
        visited.insert(cur);
        for (char c : S) {
            if (c == 'L') --cur; else ++cur;
            visited.insert(cur);
        }
        cout << visited.size() << '\n';
    }
    return 0;
}

