import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        X = int(next(it))
        S = next(it)
        visited = {X}
        cur = X
        for ch in S:
            if ch == 'L':
                cur -= 1
            else:
                cur += 1
            visited.add(cur)
        out.append(str(len(visited)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

